import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMyOrders, getNearbyVendors, getGroupBuys, joinGroupBuy } from '../services/api';
import { NEARBY_VENDORS } from '../data/defaults';
import { useAuth } from '../context/AppContext';
import toast from 'react-hot-toast';

const STATUS = {
  pending: { bg: 'rgba(255,179,71,.1)', c: '#ffb347', b: 'rgba(255,179,71,.3)', l: '⏳ Pending' },
  confirmed: { bg: 'rgba(79,195,247,.1)', c: '#4fc3f7', b: 'rgba(79,195,247,.3)', l: '✅ Confirmed' },
  delivered: { bg: 'rgba(0,230,118,.1)', c: '#00e676', b: 'rgba(0,230,118,.3)', l: '🎉 Delivered' },
  cancelled: { bg: 'rgba(255,82,82,.1)', c: '#ff5252', b: 'rgba(255,82,82,.3)', l: '❌ Cancelled' },
};

export function Orders() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getMyOrders().then(({ data }) => setOrders(data)).catch(() => toast.error('Failed')).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="flex-center" style={{ padding: 120 }}><div className="spinner" style={{ width: 40, height: 40 }} /></div>;

  return (
    <div className="page">
      <h1 style={{ fontFamily: 'Syne', fontSize: 30, fontWeight: 800, marginBottom: 24 }}>📦 My Orders</h1>
      {orders.length === 0 ? (
        <div className="flex-center" style={{ padding: 80, flexDirection: 'column', gap: 16 }}>
          <img src="https://images.unsplash.com/photo-1566576912321-d58ddd7a6088?w=300&q=80" alt="None" style={{ width: 180, borderRadius: 16, opacity: 0.4 }} />
          <h3 style={{ fontFamily: 'Syne', fontSize: 22 }}>No orders yet</h3>
          <Link to="/products" className="btn btn-primary">Start Shopping →</Link>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          {orders.map(order => {
            const s = STATUS[order.status] || STATUS.pending;
            return (
              <div key={order._id} className="card fade-in">
                <div className="flex-between" style={{ marginBottom: 14 }}>
                  <div><span style={{ fontSize: 11, color: 'var(--text2)' }}>ORDER</span><p style={{ fontFamily: 'Syne', fontWeight: 700 }}>#{order._id.slice(-8).toUpperCase()}</p></div>
                  <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                    <span style={{ fontSize: 12, color: 'var(--text2)' }}>{new Date(order.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}</span>
                    <span style={{ padding: '5px 12px', borderRadius: 20, fontSize: 12, fontWeight: 600, background: s.bg, color: s.c, border: `1px solid ${s.b}` }}>{s.l}</span>
                  </div>
                </div>
                <div style={{ display: 'flex', gap: 10, marginBottom: 14, flexWrap: 'wrap' }}>
                  {order.items?.map((item, i) => (
                    <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '7px 12px', borderRadius: 10, background: 'var(--bg3)', border: '1px solid var(--border)' }}>
                      <span style={{ fontSize: 13 }}>{item.product?.name || 'Product'} x{item.quantity}</span>
                      <span style={{ color: 'var(--accent)', fontWeight: 700, fontSize: 13 }}>Rs.{item.price * item.quantity}</span>
                    </div>
                  ))}
                </div>
                <div className="flex-between">
                  <span style={{ fontSize: 13, color: 'var(--text2)' }}>Via {order.paymentMethod?.toUpperCase()} . {order.vendor?.shopName || '--'}</span>
                  <span style={{ fontFamily: 'Syne', fontSize: 22, fontWeight: 800, color: 'var(--accent)' }}>Rs.{order.totalAmount}</span>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

export function Vendors() {
  const [vendors, setVendors] = useState(NEARBY_VENDORS);
  const [loading, setLoading] = useState(false);
  const [locating, setLocating] = useState(false);

  const findNearby = () => {
    setLocating(true);
    if (!navigator.geolocation) { toast.error('Geolocation not supported'); setLocating(false); return; }
    navigator.geolocation.getCurrentPosition(
      async ({ coords }) => {
        setLoading(true);
        try {
          const { data } = await getNearbyVendors(coords.latitude, coords.longitude);
          if (data.length > 0) setVendors(data);
          else { setVendors(NEARBY_VENDORS); toast('Showing featured vendors', { icon: 'pin' }); }
        } catch { setVendors(NEARBY_VENDORS); }
        finally { setLoading(false); setLocating(false); }
      },
      () => { toast('Showing featured vendors', { icon: 'pin' }); setLocating(false); }
    );
  };

  const imgs = [
    'https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=400&q=80',
    'https://images.unsplash.com/photo-1542838132-92c53300491e?w=400&q=80',
    'https://images.unsplash.com/photo-1488459716781-31db52582fe9?w=400&q=80',
    'https://images.unsplash.com/photo-1533900298318-6b8da08a523e?w=400&q=80',
  ];

  return (
    <div className="page">
      <div style={{ position: 'relative', borderRadius: 22, overflow: 'hidden', marginBottom: 32 }}>
        <img src="https://images.unsplash.com/photo-1519501025264-65ba15a82390?w=1200&q=80" alt="Map" style={{ width: '100%', height: 280, objectFit: 'cover', opacity: 0.2 }} />
        <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(ellipse at 50% 60%,rgba(255,92,26,.15) 0%,rgba(8,8,16,.7) 70%)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 14 }}>
          <h1 style={{ fontFamily: 'Syne', fontSize: 36, fontWeight: 800 }}>Nearby Vendors</h1>
          <p style={{ color: 'var(--text2)', fontSize: 15 }}>Discover local businesses in your area</p>
          <button className="btn btn-primary" style={{ padding: '12px 28px' }} onClick={findNearby} disabled={locating}>
            {locating ? <><div className="spinner" /> Locating...</> : 'Use My Location'}
          </button>
        </div>
      </div>

      <div className="flex-between" style={{ marginBottom: 20 }}>
        <p style={{ color: 'var(--text2)', fontSize: 13 }}>{vendors.length} vendors shown</p>
        <button className="btn btn-ghost btn-sm" onClick={findNearby}>Refresh</button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(260px,1fr))', gap: 18 }}>
        {vendors.map((v, i) => (
          <div key={v._id} className="card card-glow fade-in" style={{ padding: 0, overflow: 'hidden', animationDelay: `${i * 0.05}s` }}>
            <img src={v.img || imgs[i % imgs.length]} alt={v.shopName} style={{ width: '100%', height: 140, objectFit: 'cover' }}
              onError={e => e.target.src = imgs[i % imgs.length]} />
            <div style={{ padding: '14px 16px' }}>
              <div className="flex-between" style={{ marginBottom: 6 }}>
                <h3 style={{ fontFamily: 'Syne', fontSize: 16, fontWeight: 700 }}>{v.shopName}</h3>
                <span className="badge badge-blue" style={{ fontSize: 10 }}>{v.category}</span>
              </div>
              {v.description && <p style={{ color: 'var(--text2)', fontSize: 12, marginBottom: 10, lineHeight: 1.5 }}>{v.description}</p>}
              <div className="flex-between">
                <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
                  {v.trustScore && <span className="badge badge-orange" style={{ fontSize: 10 }}>Star {v.trustScore}</span>}
                  {v.distance && <span style={{ fontSize: 11, color: 'var(--text2)' }}>{v.distance}km</span>}
                </div>
                {v.whatsapp && <a href={`https://wa.me/${v.whatsapp}`} target="_blank" rel="noreferrer" className="btn btn-whatsapp btn-sm">Chat</a>}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export function GroupBuy() {
  const { user } = useAuth();
  const [groups, setGroups] = useState([]);
  const [loading, setLoading] = useState(true);
  const [seeding, setSeeding] = useState(false);
  const [joined, setJoined] = useState({});

  useEffect(() => { fetchGroups(); }, []);

  const fetchGroups = async () => {
    setLoading(true);
    try {
      const { data } = await getGroupBuys();
      setGroups(data);
    } catch { toast.error('Failed to load'); }
    finally { setLoading(false); }
  };

  const seedDemo = async () => {
    setSeeding(true);
    try {
      const res = await fetch('http://localhost:5000/api/groupbuy/seed-demo', { method: 'POST' });
      const data = await res.json();
      if (data.msg?.includes('created')) { toast.success(data.msg); fetchGroups(); }
      else toast.error(data.msg || 'Failed');
    } catch { toast.error('Seed failed. Add products first.'); }
    finally { setSeeding(false); }
  };

  const handleJoin = async (id) => {
    if (!user) return toast.error('Login to join');
    if (user.role === 'vendor') return toast.error('Vendors cannot join group buys');
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`http://localhost:5000/api/groupbuy/join/${id}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      if (data.unlocked) {
        toast.success('Discount Unlocked! Group target reached!', { duration: 4000 });
      } else if (data.group) {
        toast.success('Joined group buy!');
      } else {
        toast.error(data.msg || 'Failed');
      }
      setJoined(prev => ({ ...prev, [id]: true }));
      fetchGroups();
    } catch { toast.error('Failed to join'); }
  };

  const timeLeft = (exp) => {
    const d = new Date(exp) - new Date();
    if (d <= 0) return 'Expired';
    const h = Math.floor(d / 3600000);
    const m = Math.floor((d % 3600000) / 60000);
    return `${h}h ${m}m left`;
  };

  const isJoined = (group) => {
    if (joined[group._id]) return true;
    if (!user) return false;
    return group.participants?.some(p => (p._id || p) === user.id);
  };

  const getProductName = (group) => group.product?.name || group.productName || 'Product Deal';
  const getProductImage = (group) => group.product?.images?.[0] || group.productImage || null;
  const getProductPrice = (group) => group.product?.price || group.productPrice || null;
  const getVendorName = (group) => group.vendor?.shopName || group.vendorName || 'Local Vendor';
  const getCategory = (group) => group.product?.category || group.productCategory || null;

  return (
    <div className="page">
      <div style={{ position: 'relative', borderRadius: 22, overflow: 'hidden', marginBottom: 32 }}>
        <img src="https://images.unsplash.com/photo-1607082348824-0a96f2a4b9da?w=1200&q=80" alt="Group buy" style={{ width: '100%', height: 240, objectFit: 'cover', opacity: 0.18 }} />
        <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(ellipse at 30% 50%,rgba(0,230,118,.12) 0%,transparent 60%)', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 40px' }}>
          <div>
            <div className="badge badge-green" style={{ marginBottom: 12 }}>Social Commerce</div>
            <h1 style={{ fontFamily: 'Syne', fontSize: 36, fontWeight: 800 }}>Group Buying</h1>
            <p style={{ color: 'var(--text2)', marginTop: 6 }}>Join locals, unlock discounts together</p>
          </div>
          <button className="btn btn-secondary" onClick={seedDemo} disabled={seeding} style={{ flexShrink: 0 }}>
            {seeding ? <div className="spinner" /> : 'Load Demo Deals'}
          </button>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 12, marginBottom: 32 }}>
        {[
          ['1', 'Browse Deals', 'Find open group buys'],
          ['2', 'Join Group', 'Click before expiry'],
          ['3', 'Get 3-5 People', 'Reach minimum threshold'],
          ['4', 'Save Together', 'Discount for everyone!'],
        ].map(([st, ti, de]) => (
          <div key={st} className="card" style={{ textAlign: 'center', padding: '16px 12px' }}>
            <div style={{ fontSize: 11, color: 'var(--accent)', fontWeight: 700, marginBottom: 4 }}>Step {st}</div>
            <div style={{ fontFamily: 'Syne', fontWeight: 700, fontSize: 14, marginBottom: 4 }}>{ti}</div>
            <div style={{ color: 'var(--text2)', fontSize: 11 }}>{de}</div>
          </div>
        ))}
      </div>

      {loading ? (
        <div className="flex-center" style={{ padding: 80 }}><div className="spinner" style={{ width: 40, height: 40 }} /></div>
      ) : groups.length === 0 ? (
        <div className="flex-center" style={{ padding: 60, flexDirection: 'column', gap: 16 }}>
          <img src="https://images.unsplash.com/photo-1556742049-0cfed4f6a45d?w=300&q=80" alt="None" style={{ width: 160, borderRadius: 16, opacity: 0.4 }} />
          <h3 style={{ fontFamily: 'Syne', fontSize: 22 }}>No active group buys</h3>
          <p style={{ color: 'var(--text2)', fontSize: 14 }}>Click Load Demo Deals to create demo group buys</p>
          <button className="btn btn-primary" onClick={seedDemo} disabled={seeding}>
            {seeding ? <div className="spinner" /> : 'Load Demo Deals'}
          </button>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(320px,1fr))', gap: 20 }}>
          {groups.map(group => {
            const pct = Math.min((group.participants?.length / group.minUsers) * 100, 100);
            const joined_ = isJoined(group);
            const remaining = group.minUsers - (group.participants?.length || 0);
            const productImg = getProductImage(group);
            const productPrice = getProductPrice(group);
            const category = getCategory(group);

            return (
              <div key={group._id} className="card card-glow fade-in"
                style={{ border: group.status === 'successful' ? '1.5px solid var(--green)' : undefined }}>

                <div className="flex-between" style={{ marginBottom: 14 }}>
                  <span className="badge badge-green" style={{ fontSize: 13 }}>{group.discountPercent}% OFF</span>
                  <span style={{ fontSize: 12, color: 'var(--text2)' }}>{timeLeft(group.expiresAt)}</span>
                </div>

                {productImg && (
                  <img
                    src={productImg}
                    alt={getProductName(group)}
                    style={{ width: '100%', height: 120, objectFit: 'cover', borderRadius: 10, marginBottom: 12 }}
                    onError={e => e.target.style.display = 'none'}
                  />
                )}

                <h3 style={{ fontFamily: 'Syne', fontSize: 20, fontWeight: 700, marginBottom: 4 }}>
                  {getProductName(group)}
                </h3>

                <div className="flex-between" style={{ marginBottom: 8 }}>
                  <p style={{ color: 'var(--text2)', fontSize: 13, display: 'flex', alignItems: 'center', gap: 6 }}>
                    {getVendorName(group)}
                    {category && (
                      <span className="badge badge-blue" style={{ fontSize: 10 }}>{category}</span>
                    )}
                  </p>
                  {productPrice && (
                    <div>
                      <span style={{ textDecoration: 'line-through', color: 'var(--text2)', fontSize: 13 }}>
                        Rs.{productPrice}
                      </span>
                      <span style={{ color: 'var(--green)', fontWeight: 700, marginLeft: 8 }}>
                        Rs.{Math.ceil(productPrice * (1 - group.discountPercent / 100))}
                      </span>
                    </div>
                  )}
                </div>

                <div style={{ marginBottom: 14 }}>
                  <div className="flex-between" style={{ marginBottom: 6 }}>
                    <span style={{ fontSize: 13, color: 'var(--text2)' }}>
                      {group.participants?.length || 0} / {group.minUsers} joined
                    </span>
                    <span style={{ fontSize: 13, fontWeight: 700, color: pct >= 100 ? 'var(--green)' : 'var(--accent)' }}>
                      {Math.round(pct)}%
                    </span>
                  </div>
                  <div style={{ height: 12, background: 'var(--bg3)', borderRadius: 6, overflow: 'hidden', border: '1px solid var(--border)' }}>
                    <div style={{
                      height: '100%', borderRadius: 6, width: `${pct}%`,
                      background: pct >= 100
                        ? 'linear-gradient(90deg,var(--green),var(--green2))'
                        : 'linear-gradient(90deg,var(--accent),var(--accent2))',
                      transition: 'width .6s ease'
                    }} />
                  </div>
                  {remaining > 0 && group.status === 'open' && (
                    <p style={{ fontSize: 12, color: 'var(--accent2)', marginTop: 6 }}>
                      {remaining} more {remaining === 1 ? 'person' : 'people'} needed to unlock discount!
                    </p>
                  )}
                </div>

                {group.status === 'successful' ? (
                  <div style={{ padding: 14, borderRadius: 10, background: 'rgba(0,230,118,.08)', border: '1px solid rgba(0,230,118,.2)', textAlign: 'center' }}>
                    <p style={{ color: 'var(--green)', fontWeight: 700, fontSize: 16 }}>Discount Unlocked!</p>
                    <p style={{ color: 'var(--text2)', fontSize: 13, marginTop: 4 }}>
                      All {group.participants?.length} participants get {group.discountPercent}% off
                    </p>
                  </div>
                ) : joined_ ? (
                  <div style={{ padding: 12, borderRadius: 10, background: 'rgba(79,195,247,.08)', border: '1px solid rgba(79,195,247,.2)', textAlign: 'center' }}>
                    <p style={{ color: 'var(--blue)', fontWeight: 600 }}>You joined! Waiting for others...</p>
                  </div>
                ) : (
                  <button className="btn btn-primary w-full" style={{ height: 46, fontSize: 15 }}
                    onClick={() => handleJoin(group._id)}>
                    Join Group Buy - Save {group.discountPercent}%
                  </button>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
